router.use("/uploads", (req, res, next) => {
  // Basic security check
  const filePath = path.normalize(req.path);
  if (filePath.includes("..") || !filePath.startsWith("/")) {
    return res.status(403).json({ message: "Access denied" });
  }
  next();
});

